{
  "global": "Fix pylint's bad-names-rgxs option so that commas inside regular expressions (e.g. in quantifiers like {1,3}) are not treated as list delimiters, by replacing the naive CSV split with a regex-aware splitting or a different delimiter strategy.",
  "subtasks": [
    {
      "subtask": "Locate the option definition and the transformer responsible for splitting bad-names-rgxs values on commas",
      "atomics": [
        "Search the pylint source for the string 'bad-name-rgxs' or 'bad_name_rgxs' to find where the option is declared",
        "Identify the argparse action or type transformer applied to the option (e.g. _regexp_csv_transfomer or csv type)",
        "Trace how the transformer splits the raw config string into individual regex strings"
      ]
    },
    {
      "subtask": "Understand the full extent of the naive CSV split and which other options share the same transformer",
      "atomics": [
        "Find all usages of the shared csv/regexp_csv transformer to assess blast radius of any change",
        "Confirm that the split is a simple str.split(',') or re.split(',') with no awareness of regex syntax",
        "Check whether the issue reproduces both via TOML config and via CLI --bad-name-rgxs argument"
      ]
    },
    {
      "subtask": "Implement a regex-aware split that ignores commas inside curly-brace quantifiers and parenthesized groups",
      "atomics": [
        "Write or modify the transformer to use a splitting strategy that skips commas nested inside {}, (), or [] — e.g. by iterating characters and tracking brace/bracket depth",
        "Ensure the new split still correctly handles multiple comma-separated plain regex patterns with no quantifiers",
        "Apply the fix to the specific transformer used by bad-names-rgxs (and any sibling regexp-list options)"
      ]
    },
    {
      "subtask": "Add regression tests covering the comma-in-quantifier case",
      "atomics": [
        "Add a functional/config test that sets bad-name-rgxs to a pattern containing {1,3} and verifies pylint does not crash",
        "Add a unit test for the updated transformer function with inputs like '(foo{1,3})', '(foo{1,3}),(bar)', and plain 'foo,bar'",
        "Verify existing tests for bad-names-rgxs still pass after the change"
      ]
    }
  ],
  "global_atomics": [
    "Run the full pylint test suite (pytest tests/) to confirm no regressions",
    "Manually invoke pylint with the reproducer config from the bug report and confirm it no longer crashes"
  ],
  "gold_actions": {
    "global": "Modify the _regexp_csv_transfomer (or equivalent) in pylint/config/argument_type_functions.py to split on commas only at the top nesting level of the pattern string, then recompile each resulting sub-pattern as a compiled regex.",
    "subtasks": [
      {
        "subtask": "Locate the option definition and the transformer responsible for splitting bad-names-rgxs values on commas",
        "atomics": [
          "grep -r 'bad.name.rgxs' pylint/ to find the OptionsProvider declaration (likely in pylint/checkers/base/name_checker/checker.py or naming_style.py)",
          "Identify that the option type is 'regexp_csv' or equivalent, pointing to _regexp_csv_transfomer in pylint/config/argument_type_functions.py",
          "Read _regexp_csv_transfomer to confirm it calls _csv_transfomer which does re.split(r',\s*', value) on the raw string"
        ]
      },
      {
        "subtask": "Understand the full extent of the naive CSV split and which other options share the same transformer",
        "atomics": [
          "grep for _regexp_csv_transfomer usages across pylint/config/ and pylint/checkers/ to list all affected options",
          "Confirm the split is re.split(r',\\s*', value) in _csv_transfomer with no bracket/brace depth tracking",
          "Reproduce crash with python -c \"import pylint; ...\" using config bad-name-rgxs = '(foo{1,3})' to confirm root cause"
        ]
      },
      {
        "subtask": "Implement a regex-aware split that ignores commas inside curly-brace quantifiers and parenthesized groups",
        "atomics": [
          "Implement a helper _regex_aware_csv_split(value: str) -> list[str] that iterates characters, increments depth on '(' '{' '[', decrements on ')' '}' ']', and only splits on ',' when depth == 0",
          "Replace the re.split(r',\\s*', value) call inside _regexp_csv_transfomer with _regex_aware_csv_split(value), then strip whitespace from each token",
          "Leave _csv_transfomer unchanged (non-regex options) so only regexp_csv-typed options use the new depth-aware split"
        ]
      },
      {
        "subtask": "Add regression tests covering the comma-in-quantifier case",
        "atomics": [
          "Add tests/functional/b/bad_names_rgxs_comma.py + .rc containing bad-name-rgxs=(foo{1,3}) and assert pylint exits 0 with no crash",
          "Add unit tests in tests/config/test_argument_type_functions.py: assert _regexp_csv_transfomer('(foo{1,3})') == [re.compile('(foo{1,3})')], _regexp_csv_transfomer('(foo{1,3}),(bar{2,4})') == [re.compile('(foo{1,3})'), re.compile('(bar{2,4})')], and _regexp_csv_transfomer('foo,bar') == [re.compile('foo'), re.compile('bar')]",
          "Run pytest tests/config/test_argument_type_functions.py -v and pytest tests/functional/ -k bad_names to confirm all pass"
        ]
      }
    ],
    "global_atomics": [
      "Run pytest tests/ -x -q and confirm zero failures before opening the PR",
      "Execute pylint foo.py with [tool.pylint.basic] bad-name-rgxs = '(foo{1,3})' in pyproject.toml and confirm pylint starts without traceback"
    ]
  }
}
